            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("Failed to get cascade summary: ${e.message}"))
        }
    }

    /**
     * Delete asset with cascade deletion of all related data
     * Feature: 033-cascade-asset-deletion (User Story 1 - Delete Asset with All Related Data)
     *
     * DELETE /api/assets/{id}
     * Auth: ADMIN role required
     * Response: CascadeDeletionResultDto
     *
     * Related Requirements:
     * - FR-001: System MUST cascade delete vulnerabilities when asset is deleted
     * - FR-002: System MUST cascade delete ASSET-type exceptions
     * - FR-003: System MUST cascade delete vulnerability exception requests
     * - FR-011: Use pessimistic row-level locking to prevent concurrent deletion
     * - FR-013: Provide detailed structured error messages
     * - Contract: contracts/cascade-delete-api.yaml
     *
     * Error Responses:
     * - 403: User does not have ADMIN role
     * - 404: Asset not found
     * - 409: Asset is locked by another transaction (concurrent deletion)
     * - 422: Deletion would exceed timeout (forceTimeout parameter can override)
     * - 500: Internal server error or transaction timeout
     */
    @Delete("/{id}")
    @Secured("ADMIN")
    open fun delete(
        id: Long,
        @QueryValue(defaultValue = "false") forceTimeout: Boolean,
        authentication: Authentication
    ): HttpResponse<*> {
        return try {
            log.info("Cascade delete request for asset {} by user {} (forceTimeout={})",
                id, authentication.name, forceTimeout)

            // Check for non-cascade references before deletion (demands, risk assessments, risks)
            val referencingDemands = demandRepository.findByExistingAssetId(id)
            val referencingRiskAssessments = riskAssessmentRepository.findAllByInvolvedAssetId(id)
            val referencingRisks = riskRepository.findByAssetId(id)

            if (referencingDemands.isNotEmpty() || referencingRiskAssessments.isNotEmpty() || referencingRisks.isNotEmpty()) {
                val errorMessages = mutableListOf<String>()

                if (referencingDemands.isNotEmpty()) {
                    errorMessages.add("${referencingDemands.size} demand(s) reference this asset")
                }

                if (referencingRiskAssessments.isNotEmpty()) {
                    errorMessages.add("${referencingRiskAssessments.size} risk assessment(s) reference this asset")
                }

                if (referencingRisks.isNotEmpty()) {
                    errorMessages.add("${referencingRisks.size} risk(s) reference this asset")
                }

                // Get asset name for error message
                val asset = assetRepository.findById(id).orElse(null)
                val assetName = asset?.name ?: "Asset #$id"

                val detailedMessage = "Cannot delete asset '$assetName' - it is referenced by: ${errorMessages.joinToString(" and ")}. Please handle these references first."

                log.warn("Asset deletion blocked for id: {} - {}", id, detailedMessage)
                return HttpResponse.badRequest(ErrorResponse(detailedMessage))
            }

            // Perform cascade deletion
            val result = assetCascadeDeleteService.deleteAsset(
                assetId = id,
                username = authentication.name,
                forceTimeout = forceTimeout
            )

            log.info("Cascade delete successful for asset {}: {} vulns, {} exceptions, {} requests deleted",
                id, result.deletedVulnerabilities, result.deletedExceptions, result.deletedRequests)

            HttpResponse.ok(result)

        } catch (e: AssetCascadeDeleteService.AssetNotFoundException) {
            log.warn("Asset not found for deletion: {}", id)
            HttpResponse.notFound(ErrorResponse(e.message ?: "Asset not found"))

        } catch (e: PessimisticLockException) {
            log.warn("Asset {} is locked by another transaction", id)
            val asset = assetRepository.findById(id).orElse(null)
            val errorDto = assetCascadeDeleteService.buildLockedErrorDto(
                assetId = id,
                assetName = asset?.name ?: "Asset #$id",
                cause = "Asset is currently being deleted by another user"
            )
            HttpResponse.status<DeletionErrorDto>(HttpStatus.CONFLICT).body(errorDto)

        } catch (e: AssetCascadeDeleteService.TimeoutWarningException) {
            log.warn("Asset {} deletion would exceed timeout: {}s", id, e.estimatedSeconds)
            val errorDto = assetCascadeDeleteService.buildTimeoutWarningDto(
                assetId = e.assetId,
                assetName = e.assetName,
                estimatedSeconds = e.estimatedSeconds
            )
            HttpResponse.status<DeletionErrorDto>(HttpStatus.UNPROCESSABLE_ENTITY).body(errorDto)

        } catch (e: Exception) {
            log.error("Failed to delete asset {}", id, e)
            val asset = assetRepository.findById(id).orElse(null)
            val errorDto = assetCascadeDeleteService.buildInternalErrorDto(
                assetId = id,
                assetName = asset?.name ?: "Asset #$id",
                cause = "Deletion failed due to internal error",
                technicalDetails = e.message
            )
            HttpResponse.serverError<DeletionErrorDto>().body(errorDto)
        }
    }

    /**
     * Get port history for an asset
     *
     * GET /api/assets/{id}/ports
     * Auth: Any authenticated user
     * Response: PortHistoryDTO with scan history and port data
     *
     * Related to:
     * - Feature: 002-implement-a-parsing (Nmap Scan Import)
     * - Contract: specs/002-implement-a-parsing/contracts/asset-ports.yaml
     * - FR-011: Display port scan history
     */
    @Get("/{id}/ports")
    @Transactional(readOnly = true)
    open fun getPortHistory(id: Long): HttpResponse<*> {
        return try {
            log.debug("Fetching port history for asset id: {}", id)

            val asset = assetRepository.findById(id).orElse(null)
                ?: return HttpResponse.notFound(ErrorResponse("Asset not found"))

            // Get scan results ordered by discoveredAt DESC (newest first)
            val scanResults = scanResultRepository.findByAssetIdOrderByDiscoveredAtDesc(id)

            // Convert to DTOs
            val scans = scanResults.map { result ->
                val ports = result.ports.map { port ->
                    PortDTO(
                        portNumber = port.portNumber,
                        protocol = port.protocol,
                        state = port.state,
                        service = port.service,
                        version = port.version
                    )
                }

                ScanPortsDTO(
                    scanId = result.scan.id!!,
                    scanDate = result.discoveredAt,
                    scanType = result.scan.scanType,
                    ports = ports
                )
            }

            val response = PortHistoryDTO(
                assetId = asset.id!!,
                assetName = asset.name,
                scans = scans
            )

            log.debug("Found {} scans for asset {}", scans.size, asset.name)
            HttpResponse.ok(response)

        } catch (e: Exception) {
            log.error("Error fetching port history for asset id: {}", id, e)
            HttpResponse.serverError<ErrorResponse>().body(ErrorResponse("Error fetching port history: ${e.message}"))
        }
    }

    /**
     * Get vulnerabilities for an asset with access control
     * Feature: 008-create-an-additional (Workgroup-Based Access Control)
     *
     * GET /api/assets/{assetId}/vulnerabilities
     * Auth: Any authenticated user
     * Response: List<Vulnerability>
     *
     * Related to:
     * - Feature: 003-i-want-to (Vulnerability Management System)
     * - Feature: 008-create-an-additional (Workgroup-Based Access Control)
     * - FR-021: Filter asset vulnerabilities by accessibility
     */
    @Get("/{assetId}/vulnerabilities")
    @Transactional(readOnly = true)
    open fun getVulnerabilities(
        assetId: Long,
        authentication: Authentication
    ): HttpResponse<*> {
        return try {
            log.debug("Fetching vulnerabilities for asset id: {} for user: {}", assetId, authentication.name)

            // Use AssetFilterService for access-controlled vulnerability retrieval
            val vulnerabilities = assetFilterService.getAssetVulnerabilities(assetId, authentication)

            if (vulnerabilities.isEmpty()) {
                // Could mean asset not found OR user doesn't have access
                val asset = assetRepository.findById(assetId).orElse(null)
                if (asset == null) {
                    return HttpResponse.notFound(ErrorResponse("Asset not found"))
                }
                // Asset exists but user can't access it - return empty list
                log.debug("User {} has no access to asset {}", authentication.name, assetId)
            }

            log.debug("Found {} vulnerabilities for asset {}", vulnerabilities.size, assetId)
            HttpResponse.ok(vulnerabilities)

        } catch (e: Exception) {
            log.error("Error fetching vulnerabilities for asset id: {}", assetId, e)
            HttpResponse.serverError<ErrorResponse>().body(ErrorResponse("Error fetching vulnerabilities: ${e.message}"))
        }
    }

    /**
     * Export assets to Excel file
     * Feature: 029-asset-bulk-operations (User Story 2 - Export Assets to File)
     *
     * GET /api/assets/export
     * Auth: Any authenticated user
     * Response: Binary Excel file (.xlsx)
     *
     * Related Requirements:
     * - FR-010: Export assets to Excel with all fields
     * - FR-011: Apply workgroup-based access control (ADMIN sees all, non-ADMIN sees workgroup+owned)
     * - FR-012: Format export file with clear column headers
     * - FR-014: Provide user feedback during export (loading indicators handled by frontend)
     * - FR-015: Display error when no assets available
     *
     * Error Responses:
     * - 400: No assets available to export
     * - 401: User not authenticated
     * - 500: Export failed
     */
    @Get("/export")
    open fun exportAssets(authentication: Authentication): HttpResponse<*> {
        return try {
            log.info("Asset export request from user: {}", authentication.name)

            // Get assets with workgroup filtering
            val dtos = assetExportService.exportAssets(authentication)

            // Check if any assets are available
            if (dtos.isEmpty()) {
                log.warn("No assets available to export for user: {}", authentication.name)
                return HttpResponse.badRequest(ErrorResponse("No assets available to export"))
            }

            // Write to Excel
            val outputStream = assetExportService.writeToExcel(dtos)

            // Generate filename with current date
            val dateStr = java.time.LocalDate.now().toString()
            val filename = "assets_export_$dateStr.xlsx"

            log.info("Asset export successful: {} assets exported for user {}", dtos.size, authentication.name)

            // Return binary Excel file with proper headers
            HttpResponse.ok(outputStream.toByteArray())
                .header("Content-Type", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
                .header("Content-Disposition", "attachment; filename=\"$filename\"")

        } catch (e: Exception) {
            log.error("Asset export failed for user: {}", authentication.name, e)
            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("Failed to export assets: ${e.message}"))
        }
    }

    /**
     * Bulk delete all assets (ADMIN only)
     * Feature: 029-asset-bulk-operations (User Story 1 - Bulk Delete Assets)
     *
     * DELETE /api/assets/bulk
     * Auth: ADMIN role required
     * Response: BulkDeleteResult
     *
     * Related Requirements:
     * - FR-001: Delete All Assets button visible only to ADMIN users
     * - FR-003: Delete all assets when ADMIN confirms
     * - FR-006: Prevent non-ADMIN users from accessing bulk delete
     * - FR-007: Handle cascade deletion (vulnerabilities, scan results)
     * - FR-008: Execute within transaction with rollback on failure
     *
     * Error Responses:
     * - 403: User does not have ADMIN role
     * - 409: Another bulk delete operation is in progress
     * - 500: Transaction failed and was rolled back
     */
    @Delete("/bulk")
    @Secured("ADMIN")
    open fun bulkDeleteAssets(authentication: Authentication): HttpResponse<*> {
        return try {
            log.info("Bulk delete request received from user: {}", authentication.name)

            val result = assetBulkDeleteService.deleteAllAssets()

            log.info("Bulk delete successful: {}", result.message)
            HttpResponse.ok(result)

        } catch (e: com.secman.service.AssetBulkDeleteService.ConcurrentOperationException) {
            log.warn("Concurrent bulk delete attempt rejected: {}", e.message)
            HttpResponse.status<ErrorResponse>(HttpStatus.CONFLICT)
                .body(ErrorResponse(e.message ?: "Bulk asset deletion already in progress"))

        } catch (e: Exception) {
            log.error("Bulk delete failed", e)
            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("Bulk delete failed. No assets were deleted."))
        }
    }
}

package com.secman.service

import com.secman.domain.RiskAssessment
import com.secman.domain.User
import com.secman.repository.RiskAssessmentRepository
import com.secman.repository.RiskAssessmentRequirementFileRepository
import com.secman.repository.RequirementFileRepository
import jakarta.inject.Singleton
import org.slf4j.LoggerFactory
import java.nio.file.Path
import java.nio.file.Paths
import java.util.regex.Pattern

/**
 * Security service for authorization checks and input validation
 */
@Singleton
open class SecurityService(
    private val riskAssessmentRepository: RiskAssessmentRepository,
    private val requirementFileRepository: RequirementFileRepository,
    private val riskAssessmentRequirementFileRepository: RiskAssessmentRequirementFileRepository
) {

    private val logger = LoggerFactory.getLogger(SecurityService::class.java)

    companion object {
        // Input validation patterns
        private val EMAIL_PATTERN = Pattern.compile(
            "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$"
        )

        private val USERNAME_PATTERN = Pattern.compile(
            "^[a-zA-Z0-9_-]{3,50}$"
        )

        private val SAFE_FILENAME_PATTERN = Pattern.compile(
            "^[a-zA-Z0-9._-]+$"
        )

        // Dangerous file extensions that should never be allowed
        private val DANGEROUS_EXTENSIONS = setOf(
            ".exe", ".bat", ".cmd", ".com", ".scr", ".vbs", ".vbe",
            ".js", ".jse", ".wsf", ".wsh", ".ps1", ".psm1", ".psd1",
            ".msi", ".msp", ".msc", ".jar", ".app", ".deb", ".rpm",
            ".dmg", ".pkg", ".run", ".sh", ".bash", ".zsh", ".fish",
            ".html", ".htm", ".xhtml", ".svg", ".xml", ".xsl", ".xslt"
        )

        // Additional MIME type restrictions
        private val STRICTLY_ALLOWED_MIME_TYPES = setOf(
            "application/pdf",
            "application/msword",
            "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            "application/vnd.ms-excel",
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.ms-powerpoint",
            "application/vnd.openxmlformats-officedocument.presentationml.presentation",
            "text/plain",
            "text/csv",
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/bmp",
            "image/tiff"
        )

        // Maximum allowed path depth to prevent directory traversal
        private const val MAX_PATH_DEPTH = 5

        // Maximum input lengths
        const val MAX_USERNAME_LENGTH = 50
        const val MAX_EMAIL_LENGTH = 255
        const val MAX_FILENAME_LENGTH = 255
        const val MAX_TEXT_INPUT_LENGTH = 10000
        const val MAX_URL_LENGTH = 2048
    }

    /**
     * Check if user has access to a specific risk assessment
     */
    fun userHasAccessToRiskAssessment(user: User, riskAssessmentId: Long): Boolean {
        // Admins have access to everything
        if (user.isAdmin()) {
            return true
        }

        val riskAssessmentOpt = riskAssessmentRepository.findById(riskAssessmentId)
        if (riskAssessmentOpt.isEmpty) {
            return false
        }

        val riskAssessment = riskAssessmentOpt.get()

        // For now, allow access to all authenticated users for their assessments
        // In a production system, you would check:
        // - If user created the assessment
        // - If user is assigned to the demand/asset
        // - If user has specific role permissions
        // This is a simplified implementation

        return true
    }

    /**
     * Check if user has access to a specific file
     */
    fun userHasAccessToFile(user: User, fileId: Long): Boolean {
        // Admins have access to everything
        if (user.isAdmin()) {
            return true
        }

        val fileOpt = requirementFileRepository.findById(fileId)
        if (fileOpt.isEmpty) {
            return false
        }

        val file = fileOpt.get()

        // Check if user uploaded the file
        if (file.uploadedBy.id == user.id) {
            return true
        }

        // Check if file is associated with a risk assessment the user has access to
        val associationOpt = riskAssessmentRequirementFileRepository.findByFileId(fileId)
        if (associationOpt.isPresent) {
            val association = associationOpt.get()
            return userHasAccessToRiskAssessment(user, association.riskAssessment.id!!)
        }

        return false
    }

    /**
     * Check if user can delete a specific file
     */
    fun userCanDeleteFile(user: User, fileId: Long): Boolean {
        // Admins can delete any file
        if (user.isAdmin()) {
            return true
        }

        val fileOpt = requirementFileRepository.findById(fileId)
        if (fileOpt.isEmpty) {
            return false
        }

        val file = fileOpt.get()

        // Users can only delete their own files
        return file.uploadedBy.id == user.id
    }

    /**
     * Validate email format
     */
    fun isValidEmail(email: String): Boolean {
        if (email.length > MAX_EMAIL_LENGTH) {
            return false
        }
        return EMAIL_PATTERN.matcher(email).matches()
    }

    /**
     * Validate username format
     */
    fun isValidUsername(username: String): Boolean {
        if (username.length > MAX_USERNAME_LENGTH) {
            return false
        }
        return USERNAME_PATTERN.matcher(username).matches()
    }

    /**
     * Validate and sanitize filename
     */
    fun validateAndSanitizeFilename(filename: String): Pair<Boolean, String?> {
        if (filename.isBlank() || filename.length > MAX_FILENAME_LENGTH) {
            return Pair(false, "Invalid filename length")
        }

        // Check for dangerous extensions
        val lowerFilename = filename.lowercase()
        for (ext in DANGEROUS_EXTENSIONS) {
            if (lowerFilename.endsWith(ext)) {
                return Pair(false, "File type not allowed for security reasons")
            }
        }

        // Check for path traversal attempts
        if (filename.contains("..") || filename.contains("/") || filename.contains("\\")) {
            return Pair(false, "Invalid characters in filename")
        }

        // Check against safe pattern
        if (!SAFE_FILENAME_PATTERN.matcher(filename).matches()) {
            return Pair(false, "Filename contains invalid characters")
        }

        return Pair(true, null)
    }

    /**
     * Validate MIME type against strict allowlist
     */
    fun isAllowedMimeType(mimeType: String): Boolean {
        return mimeType in STRICTLY_ALLOWED_MIME_TYPES
    }

    /**
     * Validate file extension matches MIME type
     */
    fun validateFileExtensionMatchesMimeType(filename: String, mimeType: String): Boolean {
        val extension = filename.substringAfterLast('.', "").lowercase()

        return when (mimeType) {
            "application/pdf" -> extension == "pdf"
            "application/msword" -> extension == "doc"
            "application/vnd.openxmlformats-officedocument.wordprocessingml.document" -> extension == "docx"
            "application/vnd.ms-excel" -> extension == "xls"
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" -> extension == "xlsx"
            "application/vnd.ms-powerpoint" -> extension == "ppt"
            "application/vnd.openxmlformats-officedocument.presentationml.presentation" -> extension == "pptx"
            "text/plain" -> extension in setOf("txt", "text")
            "text/csv" -> extension == "csv"
            "image/jpeg" -> extension in setOf("jpg", "jpeg")
            "image/png" -> extension == "png"
            "image/gif" -> extension == "gif"
            "image/bmp" -> extension == "bmp"
            "image/tiff" -> extension in setOf("tif", "tiff")
            else -> false
        }
    }

    /**
     * Sanitize text input to prevent XSS and injection attacks
     */
    fun sanitizeTextInput(input: String, maxLength: Int = MAX_TEXT_INPUT_LENGTH): String {
        // Truncate to max length
        val truncated = if (input.length > maxLength) {
            input.substring(0, maxLength)
        } else {
            input
        }

        // Remove null bytes
        val noNullBytes = truncated.replace("\u0000", "")

        // Escape HTML special characters
        return noNullBytes
            .replace("&", "&amp;")
            .replace("<", "&lt;")
            .replace(">", "&gt;")
            .replace("\"", "&quot;")
            .replace("'", "&#x27;")
            .replace("/", "&#x2F;")
    }

    /**
     * Validate and sanitize path to prevent directory traversal
     */
    fun validatePath(path: String, basePath: String): Boolean {
        try {
            val normalizedPath = Paths.get(path).normalize()
            val normalizedBasePath = Paths.get(basePath).normalize()

            // Check if the path is within the base path
            if (!normalizedPath.startsWith(normalizedBasePath)) {
                logger.warn("Path traversal attempt detected: {} not under {}", path, basePath)
                return false
            }

            // Check path depth
            val depth = normalizedPath.nameCount - normalizedBasePath.nameCount
            if (depth > MAX_PATH_DEPTH) {
                logger.warn("Path too deep: {} levels", depth)
                return false
            }

            return true
        } catch (e: Exception) {
            logger.error("Path validation error: {}", e.message)
            return false
        }
    }

    /**
     * Validate numeric ID to prevent injection
     */
    fun isValidId(id: Long): Boolean {
        return id > 0 && id < Long.MAX_VALUE
    }

    /**
     * Validate URL format
     */
    fun isValidUrl(url: String): Boolean {
        if (url.length > MAX_URL_LENGTH) {
            return false
        }

        return try {
            val uri = java.net.URI(url)
            // Only allow http and https protocols
            uri.scheme in setOf("http", "https")
        } catch (e: Exception) {
            false
        }
    }

    /**
     * Check if string contains SQL injection patterns
     */
    fun containsSqlInjectionPattern(input: String): Boolean {
        val sqlPatterns = listOf(
            "';", "--", "/*", "*/", "xp_", "sp_", "0x",
            "union", "select", "insert", "update", "delete", "drop",
            "exec", "execute", "script", "javascript:", "onload=",
            "onerror=", "onclick=", "onmouseover="
        )

        val lowerInput = input.lowercase()
        return sqlPatterns.any { pattern -> 
            lowerInput.contains(pattern)
        }
    }

    /**
     * Generate a secure random token
     */
    fun generateSecureToken(): String {
        val random = java.security.SecureRandom()
        val bytes = ByteArray(32)
        random.nextBytes(bytes)
        return bytes.joinToString("") { "%02x".format(it) }
    }
}

package com.secman.service

import com.secman.domain.McpApiKey
import com.secman.domain.McpPermission
import com.secman.domain.User
import com.secman.dto.mcp.DelegationErrorCodes
import com.secman.dto.mcp.DelegationFailureRecord
import com.secman.dto.mcp.DelegationValidationResult
import com.secman.repository.UserRepository
import io.micronaut.context.annotation.Value
import jakarta.inject.Inject
import jakarta.inject.Singleton
import org.slf4j.LoggerFactory
import java.time.LocalDateTime
import java.util.concurrent.ConcurrentHashMap
import java.util.concurrent.ConcurrentLinkedDeque

/**
 * Service for MCP User Delegation feature.
 * Handles email passthrough validation, permission computation, and failure tracking.
 *
 * Feature: 050-mcp-user-delegation
 *
 * Delegation Flow:
 * 1. External tool passes X-MCP-User-Email header with authenticated user email
 * 2. System validates API key has delegation enabled
 * 3. System validates email domain against allowed domains
 * 4. System looks up user and computes effective permissions (intersection)
 * 5. Operations execute with delegated user's access rights
 */
@Singleton
class McpDelegationService {

    private val logger = LoggerFactory.getLogger(McpDelegationService::class.java)

    @Inject
    lateinit var userRepository: UserRepository

    /**
     * Alert threshold for failed delegation attempts.
     * When exceeded within the time window, an alert is triggered.
     */
    @Value("\${secman.mcp.delegation.alert.threshold:10}")
    var alertThreshold: Int = 10

    /**
     * Time window in minutes for threshold calculation.
     */
    @Value("\${secman.mcp.delegation.alert.window-minutes:5}")
    var alertWindowMinutes: Int = 5

    /**
     * In-memory storage for delegation failures per API key.
     * Key: API key ID, Value: Queue of failure records (sliding window)
     *
     * SECURITY NOTE (HIGH-006): This in-memory storage has limitations:
     * - Data is lost on application restart
     * - Not shared across multiple application instances in a cluster
     *
     * For production environments with high availability requirements or
     * strict security audit needs, consider implementing database-backed
     * failure tracking (e.g., DelegationFailureLog entity with scheduled cleanup).
     *
     * Current mitigations:
     * - Sliding window cleanup prevents unbounded memory growth
     * - Alert threshold triggers immediate warning for investigation
     * - MCP audit logs capture all delegation events for forensics
     */
    private val failureTracker = ConcurrentHashMap<Long, ConcurrentLinkedDeque<DelegationFailureRecord>>()

    /**
     * Mapping of user roles to implied MCP permissions.
     * Used to compute effective permissions during delegation.
     *
     * From research.md:
     * - USER: Basic read access
     * - ADMIN: All permissions
     * - VULN: Vulnerability and scan access
     * - RELEASE_MANAGER: Requirements and assessments
     * - REQ: Requirements access
     * - RISK: Assessments access
     * - SECCHAMPION: Combined Risk + Req + Vuln access
     */
    private val roleToPermissions: Map<User.Role, Set<McpPermission>> = mapOf(
        User.Role.USER to setOf(
            McpPermission.REQUIREMENTS_READ,
            McpPermission.ASSETS_READ,
            McpPermission.VULNERABILITIES_READ,
            McpPermission.TAGS_READ
        ),
        User.Role.ADMIN to McpPermission.entries.toSet(),
        User.Role.VULN to setOf(
            McpPermission.VULNERABILITIES_READ,
            McpPermission.SCANS_READ,
            McpPermission.ASSETS_READ
        ),
        User.Role.RELEASE_MANAGER to setOf(
            McpPermission.REQUIREMENTS_READ,
            McpPermission.ASSESSMENTS_READ
        ),
        User.Role.REQ to setOf(
            McpPermission.REQUIREMENTS_READ,
            McpPermission.REQUIREMENTS_WRITE,
            McpPermission.FILES_READ,
            McpPermission.TAGS_READ
        ),
        User.Role.RISK to setOf(
            McpPermission.ASSESSMENTS_READ,
            McpPermission.ASSESSMENTS_WRITE,
            McpPermission.ASSESSMENTS_EXECUTE
        ),
        User.Role.SECCHAMPION to setOf(
            McpPermission.REQUIREMENTS_READ,
            McpPermission.ASSESSMENTS_READ,
            McpPermission.ASSETS_READ,
            McpPermission.VULNERABILITIES_READ,
            McpPermission.SCANS_READ
        )
    )

    /**
     * Validate a delegation request.
     *
     * Supports both email and username as identifier:
     * - If identifier contains '@', treat as email (validate format, check domain)
     * - Otherwise, treat as username (skip email validation and domain check)
     *
     * @param apiKey The MCP API key making the request
     * @param identifier The delegated user's email address or username
     * @return DelegationValidationResult with success/failure details
     */
    fun validateDelegation(apiKey: McpApiKey, identifier: String): DelegationValidationResult {
        logger.debug("Validating delegation: apiKeyId={}, identifier={}", apiKey.id, identifier)

        // Check if delegation is enabled for this API key
        if (!apiKey.delegationEnabled) {
            logger.debug("Delegation not enabled for API key: {}", apiKey.keyId)
            recordFailure(apiKey.id, identifier, DelegationErrorCodes.DELEGATION_NOT_ENABLED)
            return DelegationValidationResult.failure(
                DelegationErrorCodes.DELEGATION_NOT_ENABLED,
                "Delegation is not enabled for this API key"
            )
        }

        // Determine if identifier is email or username
        val isEmail = identifier.contains("@")

        // Look up user based on identifier type
        val user = if (isEmail) {
            // Email path: validate format and domain, then lookup
            if (!isValidEmail(identifier)) {
                logger.debug("Invalid email format for delegation: {}", identifier)
                recordFailure(apiKey.id, identifier, DelegationErrorCodes.DELEGATION_INVALID_EMAIL)
                return DelegationValidationResult.failure(
                    DelegationErrorCodes.DELEGATION_INVALID_EMAIL,
                    "Invalid email format: $identifier"
                )
            }

            if (!apiKey.isDelegationAllowedForEmail(identifier)) {
                logger.warn("Domain rejected for delegation: email={}, apiKey={}", identifier, apiKey.keyId)
                recordFailure(apiKey.id, identifier, DelegationErrorCodes.DELEGATION_DOMAIN_REJECTED)
                return DelegationValidationResult.failure(
                    DelegationErrorCodes.DELEGATION_DOMAIN_REJECTED,
                    "Email domain is not in the allowed list for this API key"
                )
            }

            userRepository.findByEmailIgnoreCase(identifier).orElse(null)
        } else {
            // Username path: skip email validation and domain check
            logger.debug("Using username lookup for delegation: {}", identifier)
            userRepository.findByUsername(identifier).orElse(null)
        }

        if (user == null) {
            val identifierType = if (isEmail) "email" else "username"
            logger.warn("User not found for delegation: {}={}", identifierType, identifier)
            recordFailure(apiKey.id, identifier, DelegationErrorCodes.DELEGATION_USER_NOT_FOUND)
            return DelegationValidationResult.failure(
                DelegationErrorCodes.DELEGATION_USER_NOT_FOUND,
                "User with $identifierType '$identifier' not found"
            )
        }

        // Compute effective permissions (intersection of user roles and API key permissions)
        val effectivePermissions = computeEffectivePermissions(user, apiKey)

        logger.info(
            "Delegation validated successfully: identifier={}, user={}, apiKey={}, effectivePermissions={}",
            identifier, user.username, apiKey.keyId, effectivePermissions.size
        )

        return DelegationValidationResult.success(user, effectivePermissions)
    }

    /**
     * Compute the effective permissions for a delegated user.
     *
     * The effective permissions are the INTERSECTION of:
     * 1. Permissions implied by the user's roles (mapped via roleToPermissions)
     * 2. Permissions granted to the API key
     *
     * This implements defense-in-depth: the delegated user can never have
     * more permissions than either their roles allow OR the API key allows.
     *
     * @param user The delegated user
     * @param apiKey The MCP API key
     * @return Set of effective MCP permissions
     */
    fun computeEffectivePermissions(user: User, apiKey: McpApiKey): Set<McpPermission> {
        // Get permissions implied by user's roles
        val userImpliedPermissions = user.roles
            .flatMap { role -> roleToPermissions[role] ?: emptySet() }
            .toSet()

        // Get API key's permissions
        val apiKeyPermissions = apiKey.getPermissionSet()

        // Compute intersection
        val effectivePermissions = userImpliedPermissions.intersect(apiKeyPermissions)

        logger.debug(
            "Computed effective permissions: user={}, userPermissions={}, apiKeyPermissions={}, effective={}",
            user.email,
            userImpliedPermissions.size,
            apiKeyPermissions.size,
            effectivePermissions.size
        )

        return effectivePermissions
    }

    /**
     * Get the permissions implied by a user's roles.
     *
     * @param user The user
     * @return Set of MCP permissions implied by the user's roles
     */
    fun getUserImpliedPermissions(user: User): Set<McpPermission> {
        return user.roles
            .flatMap { role -> roleToPermissions[role] ?: emptySet() }
            .toSet()
    }

    /**
     * Record a delegation failure for threshold tracking.
     *
     * @param apiKeyId The ID of the API key
     * @param email The email that failed delegation
     * @param reason The failure reason code
     */
    private fun recordFailure(apiKeyId: Long, email: String, reason: String) {
        val record = DelegationFailureRecord(
            apiKeyId = apiKeyId,
            timestamp = LocalDateTime.now(),
            email = email,
            reason = reason
        )

        val failures = failureTracker.computeIfAbsent(apiKeyId) { ConcurrentLinkedDeque() }
        failures.addLast(record)

        // Clean up old entries outside the time window
        val windowStart = LocalDateTime.now().minusMinutes(alertWindowMinutes.toLong())
        while (failures.peekFirst()?.timestamp?.isBefore(windowStart) == true) {
            failures.pollFirst()
        }

        // Check if threshold is exceeded
        if (failures.size >= alertThreshold) {
            triggerAlert(apiKeyId, failures.size)
        }
    }

    /**
     * Trigger an alert for excessive delegation failures.
     * Currently logs at WARN level; can be extended to send notifications.
     *
     * @param apiKeyId The ID of the API key
     * @param failureCount The number of failures in the time window
     */
    private fun triggerAlert(apiKeyId: Long, failureCount: Int) {
        logger.warn(
            "DELEGATION ALERT: API key {} has {} failed delegation attempts in the last {} minutes. " +
            "Threshold: {}. Possible abuse or misconfiguration.",
            apiKeyId, failureCount, alertWindowMinutes, alertThreshold
        )
        // TODO: Integrate with notification service if available
    }

    /**
     * Get the current failure count for an API key within the time window.
     * Useful for monitoring and testing.
     *
     * @param apiKeyId The ID of the API key
     * @return The number of failures in the current time window
     */
    fun getFailureCount(apiKeyId: Long): Int {
        val failures = failureTracker[apiKeyId] ?: return 0
        val windowStart = LocalDateTime.now().minusMinutes(alertWindowMinutes.toLong())
        return failures.count { it.timestamp.isAfter(windowStart) }
    }

    /**
     * Clear failure records for an API key.
     * Useful for testing and administrative purposes.
     *
     * @param apiKeyId The ID of the API key
     */
    fun clearFailures(apiKeyId: Long) {
        failureTracker.remove(apiKeyId)
    }

    /**
     * Validate email format.
     *
     * @param email The email to validate
     * @return true if the email format is valid
     */
    private fun isValidEmail(email: String): Boolean {
        if (email.isBlank()) return false
        val emailRegex = "^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}\$".toRegex()
        return emailRegex.matches(email)
    }

    /**
     * Check if delegation would be allowed for a given API key and email.
     * Does NOT record failures or look up the user - use for validation preview.
     *
     * @param apiKey The MCP API key
     * @param email The email to check
     * @return true if delegation would be allowed (structurally), false otherwise
     */
    fun isDelegationStructurallyAllowed(apiKey: McpApiKey, email: String): Boolean {
        return apiKey.delegationEnabled &&
               isValidEmail(email) &&
               apiKey.isDelegationAllowedForEmail(email)
    }
}

package com.secman.controller

import com.secman.domain.*
import com.secman.repository.*
import io.micronaut.core.annotation.Nullable
import io.micronaut.http.HttpResponse
import io.micronaut.http.HttpStatus
import io.micronaut.http.annotation.*
import io.micronaut.scheduling.TaskExecutors
import io.micronaut.scheduling.annotation.ExecuteOn
import io.micronaut.security.annotation.Secured
import io.micronaut.security.rules.SecurityRule
import io.micronaut.serde.annotation.Serdeable
import io.micronaut.transaction.annotation.Transactional
import jakarta.persistence.EntityManager
import jakarta.validation.Valid
import jakarta.validation.constraints.NotBlank
import jakarta.validation.constraints.NotNull
import jakarta.validation.constraints.Size
import org.slf4j.LoggerFactory
import java.time.LocalDateTime

@Controller("/api/demands")
@Secured(SecurityRule.IS_AUTHENTICATED)
@ExecuteOn(TaskExecutors.BLOCKING)
open class DemandController(
    private val demandRepository: DemandRepository,
    private val assetRepository: AssetRepository,
    private val userRepository: UserRepository,
    private val entityManager: EntityManager
) {

    private val log = LoggerFactory.getLogger(DemandController::class.java)

    @Serdeable
    data class CreateDemandRequest(
        @NotBlank @Size(max = 255) val title: String,
        @Nullable val description: String? = null,
        @NotNull val demandType: DemandType,
        @Nullable val existingAssetId: Long? = null,
        @Nullable @Size(max = 255) val newAssetName: String? = null,
        @Nullable @Size(max = 100) val newAssetType: String? = null,
        @Nullable @Size(max = 45) val newAssetIp: String? = null,
        @Nullable @Size(max = 255) val newAssetOwner: String? = null,
        @Nullable val newAssetDescription: String? = null,
        @Nullable val businessJustification: String? = null,
        @Nullable val priority: Priority? = Priority.MEDIUM,
        @NotNull val requestorId: Long
    )

    @Serdeable
    data class UpdateDemandRequest(
        @Nullable @Size(max = 255) val title: String? = null,
        @Nullable val description: String? = null,
        @Nullable val existingAssetId: Long? = null,
        @Nullable @Size(max = 255) val newAssetName: String? = null,
        @Nullable @Size(max = 100) val newAssetType: String? = null,
        @Nullable @Size(max = 45) val newAssetIp: String? = null,
        @Nullable @Size(max = 255) val newAssetOwner: String? = null,
        @Nullable val newAssetDescription: String? = null,
        @Nullable val businessJustification: String? = null,
        @Nullable val priority: Priority? = null,
        @Nullable val status: DemandStatus? = null
    )

    @Serdeable
    data class ApproveDemandRequest(
        @NotNull val approved: Boolean,
        @Nullable val rejectionReason: String? = null
    )

    @Serdeable
    data class DemandFilterRequest(
        @Nullable val status: DemandStatus? = null,
        @Nullable val demandType: DemandType? = null,
        @Nullable val priority: Priority? = null,
        @Nullable val requestorId: Long? = null
    )

    @Serdeable
    data class ErrorResponse(
        val error: String,
        val message: String
    )

    @Serdeable
    data class DemandSummary(
        val totalDemands: Long,
        val pendingDemands: Long,
        val approvedDemands: Long,
        val rejectedDemands: Long,
        val changeDemands: Long,
        val createNewDemands: Long
    )

    @Get
    @Transactional(readOnly = true)
    open fun listDemands(@QueryValue @Nullable status: DemandStatus?,
                        @QueryValue @Nullable demandType: DemandType?,
                        @QueryValue @Nullable priority: Priority?,
                        @QueryValue @Nullable requestorId: Long?): HttpResponse<List<Demand>> {
        return try {
            log.debug("Fetching demands with filters - status: {}, type: {}, priority: {}, requestor: {}", 
                     status, demandType, priority, requestorId)

            val demands = if (status != null || demandType != null || priority != null || requestorId != null) {
                demandRepository.findWithFilters(status, demandType, priority, requestorId)
            } else {
                entityManager.createQuery(
                    """
                    SELECT DISTINCT d FROM Demand d 
                    LEFT JOIN FETCH d.requestor 
                    LEFT JOIN FETCH d.approver 
                    LEFT JOIN FETCH d.existingAsset 
                    ORDER BY d.requestedDate DESC
                    """,
                    Demand::class.java
                ).resultList
            }

            log.debug("Found {} demands", demands.size)
            HttpResponse.ok(demands)
        } catch (e: Exception) {
            log.error("Error fetching demands", e)
            HttpResponse.serverError<List<Demand>>()
        }
    }

    @Get("/{id}")
    @Transactional(readOnly = true)
    open fun getDemand(id: Long): HttpResponse<*> {
        return try {
            log.debug("Fetching demand with id: {}", id)

            val demand = entityManager.createQuery(
                """
                SELECT d FROM Demand d 
                LEFT JOIN FETCH d.requestor 
                LEFT JOIN FETCH d.approver 
                LEFT JOIN FETCH d.existingAsset 
                WHERE d.id = :id
                """,
                Demand::class.java
            ).setParameter("id", id).resultList.firstOrNull()

            if (demand != null) {
                log.debug("Found demand: {}", demand.id)
                HttpResponse.ok(demand)
            } else {
                log.debug("Demand not found with id: {}", id)
                HttpResponse.notFound(ErrorResponse("NOT_FOUND", "Demand not found"))
            }
        } catch (e: Exception) {
            log.error("Error fetching demand with id: {}", id, e)
            HttpResponse.serverError<Any>()
        }
    }

    @Get("/summary")
    @Transactional(readOnly = true)
    open fun getDemandSummary(): HttpResponse<DemandSummary> {
        return try {
            log.debug("Generating demand summary")

            val summary = DemandSummary(
                totalDemands = demandRepository.count(),
                pendingDemands = demandRepository.countByStatus(DemandStatus.PENDING),
                approvedDemands = demandRepository.countByStatus(DemandStatus.APPROVED),
                rejectedDemands = demandRepository.countByStatus(DemandStatus.REJECTED),
                changeDemands = demandRepository.countByDemandType(DemandType.CHANGE),
                createNewDemands = demandRepository.countByDemandType(DemandType.CREATE_NEW)
            )

            log.debug("Generated demand summary: {}", summary)
            HttpResponse.ok(summary)
        } catch (e: Exception) {
            log.error("Error generating demand summary", e)
            HttpResponse.serverError<DemandSummary>()
        }
    }

    @Get("/approved/available")
    @Transactional(readOnly = true)
    open fun getApprovedDemandsForRiskAssessment(): HttpResponse<List<Demand>> {
        return try {
            log.debug("Fetching approved demands available for risk assessment")

            val demands = demandRepository.findApprovedDemandsWithoutRiskAssessment()

            // Force loading of related entities
            demands.forEach { demand ->
                demand.requestor.username
                demand.approver?.username
                demand.existingAsset?.name
            }

            log.debug("Found {} approved demands available for risk assessment", demands.size)
            HttpResponse.ok(demands)
        } catch (e: Exception) {
            log.error("Error fetching approved demands for risk assessment", e)
            HttpResponse.serverError<List<Demand>>()
        }
    }

    @Post
    @Transactional
    open fun createDemand(@Valid @Body request: CreateDemandRequest): HttpResponse<*> {
        return try {
            log.debug("Creating demand: {}", request.title)

            // Validate requestor exists
            val requestor = userRepository.findById(request.requestorId).orElse(null)
                ?: return HttpResponse.badRequest(ErrorResponse("VALIDATION_ERROR", "Requestor not found"))

            // Validate asset information based on demand type
            val existingAsset = if (request.demandType == DemandType.CHANGE) {
                request.existingAssetId?.let { assetId ->
                    assetRepository.findById(assetId).orElse(null)
                        ?: return HttpResponse.badRequest(ErrorResponse("VALIDATION_ERROR", "Existing asset not found"))
                } ?: return HttpResponse.badRequest(ErrorResponse("VALIDATION_ERROR", "Existing asset ID required for CHANGE demand"))
            } else null

            // Validate new asset information for CREATE_NEW demands
            if (request.demandType == DemandType.CREATE_NEW) {
                if (request.newAssetName.isNullOrBlank() || 
                    request.newAssetType.isNullOrBlank() || 
                    request.newAssetOwner.isNullOrBlank()) {
                    return HttpResponse.badRequest(ErrorResponse("VALIDATION_ERROR", 
                        "New asset name, type, and owner are required for CREATE_NEW demand"))
                }
            }

            // Create demand
            val demand = Demand(
                title = request.title.trim(),
                description = request.description?.trim()?.takeIf { it.isNotBlank() },
                demandType = request.demandType,
                existingAsset = existingAsset,
                newAssetName = request.newAssetName?.trim()?.takeIf { it.isNotBlank() },
                newAssetType = request.newAssetType?.trim()?.takeIf { it.isNotBlank() },
                newAssetIp = request.newAssetIp?.trim()?.takeIf { it.isNotBlank() },
                newAssetOwner = request.newAssetOwner?.trim()?.takeIf { it.isNotBlank() },
                newAssetDescription = request.newAssetDescription?.trim()?.takeIf { it.isNotBlank() },
                businessJustification = request.businessJustification?.trim()?.takeIf { it.isNotBlank() },
                priority = request.priority ?: Priority.MEDIUM,
                requestor = requestor
            )

            val savedDemand = demandRepository.save(demand)

            // Fetch the complete demand with all relationships
            val completeDemand = entityManager.createQuery(
                """
                SELECT d FROM Demand d 
                LEFT JOIN FETCH d.requestor 
                LEFT JOIN FETCH d.existingAsset 
                WHERE d.id = :id
                """,
                Demand::class.java
            ).setParameter("id", savedDemand.id)
             .singleResult

            log.info("Created demand with id: {}", completeDemand.id)
            HttpResponse.status<Demand>(HttpStatus.CREATED).body(completeDemand)
        } catch (e: Exception) {
            log.error("Error creating demand", e)
            HttpResponse.serverError<Any>()
        }
    }

    @Put("/{id}")
    @Transactional
    open fun updateDemand(id: Long, @Valid @Body request: UpdateDemandRequest): HttpResponse<*> {
        return try {
            log.debug("Updating demand with id: {}", id)

            val demand = demandRepository.findById(id).orElse(null)
                ?: return HttpResponse.notFound(ErrorResponse("NOT_FOUND", "Demand not found"))

            // Update fields if provided
            request.title?.let { demand.title = it.trim() }
            request.description?.let { demand.description = it.trim().takeIf { it.isNotBlank() } }
            request.businessJustification?.let { demand.businessJustification = it.trim().takeIf { it.isNotBlank() } }
            request.priority?.let { demand.priority = it }
            request.status?.let { demand.status = it }

            // Update asset information based on demand type
            if (demand.demandType == DemandType.CHANGE) {
                request.existingAssetId?.let { assetId ->
                    val asset = assetRepository.findById(assetId).orElse(null)
                        ?: return HttpResponse.badRequest(ErrorResponse("VALIDATION_ERROR", "Asset not found"))
                    demand.existingAsset = asset
                }
            } else if (demand.demandType == DemandType.CREATE_NEW) {
                request.newAssetName?.let { demand.newAssetName = it.trim().takeIf { it.isNotBlank() } }
                request.newAssetType?.let { demand.newAssetType = it.trim().takeIf { it.isNotBlank() } }
                request.newAssetIp?.let { demand.newAssetIp = it.trim().takeIf { it.isNotBlank() } }
                request.newAssetOwner?.let { demand.newAssetOwner = it.trim().takeIf { it.isNotBlank() } }
                request.newAssetDescription?.let { demand.newAssetDescription = it.trim().takeIf { it.isNotBlank() } }
            }

            val updatedDemand = demandRepository.update(demand)

            // Fetch the complete demand with all relationships
            val completeDemand = entityManager.createQuery(
                """
                SELECT d FROM Demand d 
                LEFT JOIN FETCH d.requestor 
                LEFT JOIN FETCH d.approver 
                LEFT JOIN FETCH d.existingAsset 
                WHERE d.id = :id
                """,
                Demand::class.java
            ).setParameter("id", updatedDemand.id)
             .singleResult

            log.info("Updated demand with id: {}", id)
            HttpResponse.ok(completeDemand)
        } catch (e: Exception) {
            log.error("Error updating demand with id: {}", id, e)
            HttpResponse.serverError<Any>()
        }
    }

    @Post("/{id}/approve")
    @Transactional
    open fun approveDemand(id: Long, @Valid @Body request: ApproveDemandRequest): HttpResponse<*> {
        return try {
            log.debug("Processing approval for demand: {}", id)

            val demand = demandRepository.findById(id).orElse(null)
                ?: return HttpResponse.notFound(ErrorResponse("NOT_FOUND", "Demand not found"))

            if (demand.status != DemandStatus.PENDING) {
                return HttpResponse.badRequest(ErrorResponse("INVALID_STATE", 
                    "Only pending demands can be approved or rejected"))
            }

            // TODO: Get current user from security context
            // For now, we'll need to pass approver ID or get from context
            // This is a simplification - in production, you'd get the approver from the security context

            if (request.approved) {
                demand.status = DemandStatus.APPROVED
                demand.approvedDate = LocalDateTime.now()
                demand.rejectionReason = null
                log.info("Approved demand: {}", id)
            } else {
                demand.status = DemandStatus.REJECTED
                demand.rejectionReason = request.rejectionReason?.trim()?.takeIf { it.isNotBlank() }
                    ?: "No reason provided"
                log.info("Rejected demand: {} with reason: {}", id, demand.rejectionReason)
            }

            val updatedDemand = demandRepository.update(demand)

            // Fetch the complete demand with all relationships
            val completeDemand = entityManager.createQuery(
                """
                SELECT d FROM Demand d 
                LEFT JOIN FETCH d.requestor 
                LEFT JOIN FETCH d.approver 
                LEFT JOIN FETCH d.existingAsset 
                WHERE d.id = :id
                """,
                Demand::class.java
            ).setParameter("id", updatedDemand.id)
             .singleResult

            HttpResponse.ok(completeDemand)
        } catch (e: Exception) {
            log.error("Error processing approval for demand: {}", id, e)
            HttpResponse.serverError<Any>()
        }
    }

    @Delete("/{id}")
    @Transactional
    open fun deleteDemand(id: Long): HttpResponse<*> {
        return try {
            log.debug("Deleting demand with id: {}", id)

            val demand = demandRepository.findById(id).orElse(null)
                ?: return HttpResponse.notFound(ErrorResponse("NOT_FOUND", "Demand not found"))

            // Check if demand has associated risk assessments
            val hasRiskAssessments = entityManager.createQuery(
                "SELECT COUNT(ra) FROM RiskAssessment ra WHERE ra.demand.id = :demandId",
                Long::class.java
            ).setParameter("demandId", id).singleResult > 0

            if (hasRiskAssessments) {
                return HttpResponse.badRequest(ErrorResponse("VALIDATION_ERROR", 
                    "Cannot delete demand with associated risk assessments"))
            }

            demandRepository.delete(demand)

            log.info("Deleted demand with id: {}", id)
            HttpResponse.ok(mapOf("message" to "Demand deleted successfully"))
        } catch (e: Exception) {
            log.error("Error deleting demand with id: {}", id, e)
            HttpResponse.serverError<Any>()
        }
    }
}

package com.secman.domain

import com.fasterxml.jackson.annotation.JsonIgnore
import io.micronaut.serde.annotation.Serdeable
import jakarta.persistence.*
import jakarta.validation.constraints.NotNull
import java.time.LocalDate
import java.time.LocalDateTime

@Entity
@Table(
    name = "risk_assessment",
    indexes = [
        Index(name = "idx_risk_assessment_basis", columnList = "assessment_basis_type, assessment_basis_id"),
        Index(name = "idx_risk_assessment_assessor", columnList = "assessor_id"),
        Index(name = "idx_risk_assessment_requestor", columnList = "requestor_id"),
        Index(name = "idx_risk_assessment_status", columnList = "status"),
        Index(name = "idx_risk_assessment_dates", columnList = "start_date, end_date")
    ]
)
@Serdeable
data class RiskAssessment(
    @Id
    @GeneratedValue
    var id: Long? = null,

    @Column(name = "start_date", nullable = false)
    @NotNull
    var startDate: LocalDate,

    @Column(name = "end_date", nullable = false)
    @NotNull
    var endDate: LocalDate,

    @Column(name = "status", length = 50)
    var status: String = "STARTED",

    @Column(name = "notes", length = 1024)
    var notes: String? = null,

    @Column(name = "is_release_locked")
    var isReleaseLocked: Boolean = false,

    @Column(name = "content_snapshot_taken")
    var contentSnapshotTaken: Boolean = false,

    @Column(name = "release_locked_at")
    var releaseLockedAt: LocalDateTime? = null,

    // New unified approach: Assessment basis can be either DEMAND or ASSET
    @Enumerated(EnumType.STRING)
    @Column(name = "assessment_basis_type", nullable = false)
    @NotNull
    var assessmentBasisType: AssessmentBasisType,

    @Column(name = "assessment_basis_id", nullable = false)
    @NotNull
    var assessmentBasisId: Long,

    // Legacy fields for backward compatibility during migration
    @ManyToOne
    @JoinColumn(name = "demand_id")
    @Deprecated("Use assessmentBasisType and assessmentBasisId instead. This field is kept for migration compatibility.")
    var demand: Demand? = null,

    @ManyToOne
    @JoinColumn(name = "asset_id")
    @Deprecated("Use assessmentBasisType and assessmentBasisId instead. This field is kept for migration compatibility.")
    var asset: Asset? = null,

    @ManyToOne
    @JoinColumn(name = "assessor_id", nullable = false)
    @NotNull
    var assessor: User,

    @ManyToOne
    @JoinColumn(name = "requestor_id", nullable = false)
    @NotNull
    var requestor: User,

    @ManyToOne
    @JoinColumn(name = "respondent_id")
    var respondent: User? = null,

    @ManyToOne
    @JoinColumn(name = "release_id")
    @JsonIgnore
    var lockedRelease: Release? = null,

    @ManyToMany
    @JoinTable(
        name = "risk_assessment_usecase",
        joinColumns = [JoinColumn(name = "risk_assessment_id")],
        inverseJoinColumns = [JoinColumn(name = "usecase_id")]
    )
    var useCases: MutableSet<UseCase> = mutableSetOf(),

    @Column(name = "created_at", nullable = false, updatable = false)
    var createdAt: LocalDateTime? = null,

    @Column(name = "updated_at", nullable = false)
    var updatedAt: LocalDateTime? = null
) {
    // Primary constructor for demand-based risk assessments
    constructor(
        startDate: LocalDate,
        endDate: LocalDate,
        demand: Demand,
        assessor: User,
        requestor: User
    ) : this(
        startDate = startDate,
        endDate = endDate,
        assessmentBasisType = AssessmentBasisType.DEMAND,
        assessmentBasisId = demand.id ?: throw IllegalArgumentException("Demand must have an ID"),
        assessor = assessor,
        requestor = requestor,
        status = "STARTED",
        demand = demand,
        asset = null
    )

    // Constructor for asset-based risk assessments
    constructor(
        startDate: LocalDate,
        endDate: LocalDate,
        asset: Asset,
        assessor: User,
        requestor: User
    ) : this(
        startDate = startDate,
        endDate = endDate,
        assessmentBasisType = AssessmentBasisType.ASSET,
        assessmentBasisId = asset.id ?: throw IllegalArgumentException("Asset must have an ID"),
        assessor = assessor,
        requestor = requestor,
        status = "STARTED",
        demand = null,
        asset = asset
    )

    @PrePersist
    fun onCreate() {
        val now = LocalDateTime.now()
        createdAt = now
        updatedAt = now
    }

    @PreUpdate
    fun onUpdate() {
        updatedAt = LocalDateTime.now()
    }

    /**
     * Gets the demand associated with this risk assessment if basis type is DEMAND
     */
    @Suppress("DEPRECATION")
    fun getDemandBasis(): Demand? {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> demand ?: throw IllegalStateException("Demand not loaded for DEMAND basis type")
            AssessmentBasisType.ASSET -> null
        }
    }

    /**
     * Gets the asset associated with this risk assessment if basis type is ASSET
     */
    @Suppress("DEPRECATION")
    fun getAssetBasis(): Asset? {
        return when (assessmentBasisType) {
            AssessmentBasisType.ASSET -> asset ?: throw IllegalStateException("Asset not loaded for ASSET basis type")
            AssessmentBasisType.DEMAND -> null
        }
    }

    /**
     * Gets the actual asset for this risk assessment, considering both demand and direct asset basis
     */
    fun getAssociatedAsset(): Asset? {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> {
                val demandBasis = getDemandBasis()
                when (demandBasis?.demandType) {
                    DemandType.CHANGE -> demandBasis.existingAsset
                    DemandType.CREATE_NEW -> null // New assets don't exist yet
                    null -> null
                }
            }
            AssessmentBasisType.ASSET -> getAssetBasis()
        }
    }

    /**
     * Gets the asset name for display purposes
     */
    fun getAssetName(): String {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> getDemandBasis()?.getAssetName() ?: "Unknown Asset"
            AssessmentBasisType.ASSET -> getAssetBasis()?.name ?: "Unknown Asset"
        }
    }

    /**
     * Gets the asset type for display purposes
     */
    fun getAssetType(): String {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> getDemandBasis()?.getAssetType() ?: "Unknown"
            AssessmentBasisType.ASSET -> getAssetBasis()?.type ?: "Unknown"
        }
    }

    /**
     * Gets the description of what is being assessed
     */
    fun getBasisDescription(): String {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> getDemandBasis()?.title ?: "Unknown Demand"
            AssessmentBasisType.ASSET -> getAssetBasis()?.name ?: "Unknown Asset"
        }
    }

    /**
     * Gets the owner for display purposes
     */
    fun getAssetOwner(): String {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> getDemandBasis()?.getAssetOwner() ?: "Unknown"
            AssessmentBasisType.ASSET -> getAssetBasis()?.owner ?: "Unknown"
        }
    }

    /**
     * Validates that the assessment basis configuration is consistent
     */
    @Suppress("DEPRECATION")
    fun validateBasisConsistency(): Boolean {
        return when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> {
                demand != null &&
                demand?.id == assessmentBasisId &&
                asset == null
            }
            AssessmentBasisType.ASSET -> {
                asset != null &&
                asset?.id == assessmentBasisId &&
                demand == null
            }
        }
    }

    /**
     * Gets validation errors for the assessment basis configuration
     */
    @Suppress("DEPRECATION")
    fun getBasisValidationErrors(): List<String> {
        val errors = mutableListOf<String>()

        when (assessmentBasisType) {
            AssessmentBasisType.DEMAND -> {
                if (demand == null) {
                    errors.add("Demand entity must be loaded for DEMAND basis type")
                }
                if (demand?.id != assessmentBasisId) {
                    errors.add("Demand ID (${demand?.id}) must match assessmentBasisId ($assessmentBasisId)")
                }
                if (asset != null) {
                    errors.add("Asset must be null for DEMAND basis type")
                }
            }
            AssessmentBasisType.ASSET -> {
                if (asset == null) {
                    errors.add("Asset entity must be loaded for ASSET basis type")
                }
                if (asset?.id != assessmentBasisId) {
                    errors.add("Asset ID (${asset?.id}) must match assessmentBasisId ($assessmentBasisId)")
                }
                if (demand != null) {
                    errors.add("Demand must be null for ASSET basis type")
                }
            }
        }

        return errors
    }

    override fun toString(): String {
        return "RiskAssessment(id=$id, startDate=$startDate, endDate=$endDate, status='$status', basisType=$assessmentBasisType, basis=${getBasisDescription()})"
    }

    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is RiskAssessment) return false
        return id != null && id == other.id
    }

    override fun hashCode(): Int {
        return id?.hashCode() ?: 0
    }
}

